<template>
  <div id="app">
    <div class="topElements" :class="[noneSelected]">
      <!-- animation -->
      <lottie :options="defaultOptions" :height="350" :width="350"/>
      <Navbar :articleData="articleData" @backgroundColor="background"/>

      <span class="breaker"></span>
      <transition name="content-holder">
        <router-view :key="$route.path"/>
      </transition>
    </div>
      <Footer />
  </div>
</template>

<script>
import Navbar from '@/components/Nav.vue'

import Footer from '@/components/Footer.vue'

import Lottie from 'vue-lottie'

import * as animationData from '@/assets/animation/LL2.json';

export default {
  components: {
    Navbar,
    Footer,
    'lottie': Lottie
  },
  data(){
    return {
      articleData: null,

      // animation details: 

      defaultOptions: {
        animationData: animationData.default,
        loop: false,
        width: '350',
        height: '350',
        autoplay: true
        },

      //   set up a variable for the local host as this will change later when the enviroment moves online
      local: 'http://localhost:1337/',

      // set up for the web useage of the fetch command << this is for the live site
      enviroment: 'https://littleleo-cms.herokuapp.com/',

      backgrounds: 
      [
      'linear-gradient(45deg, #e96443, #904e95)', 
      'linear-gradient(45deg, #3a7bd5, #3a6073)', 
      'linear-gradient(45deg, #f7ff00, #db36a4)',
      
      'linear-gradient(45deg, #B24592, #F15F79)',
      'linear-gradient(45deg, #FFB75E, #ED8F03)',
      'linear-gradient(45deg, #673AB7, #512DA8)',

      'linear-gradient(45deg, #fc00ff, #00dbde)',
      'linear-gradient(45deg, #00C9FF, #92FE9D)',
      ],

      noneSelected: 'defaultBG', // << default background color

      backgroundColor: null,

    }
  },
  created(){
    fetch(`${this.enviroment}languages`)
    .then(responce => responce.json())
    .then(data => {this.articleData = data})
  },
  mounted(){
    // Set random background color, keeps the site looking fresh 

    document.querySelector('.topElements').style.background = this.backgrounds[Math.floor(Math.random() * this.backgrounds.length)];
  },
  methods: {
    background(id){
        let bg_id = id-1 // -1 so the number is inline with the array starting at 0 not 1
        this.backgroundColor = this.backgrounds[bg_id]
    }
  },
  // changes back ground color 
  watch: {
    backgroundColor: function(){
      document.querySelector('.topElements').style.background = this.backgroundColor
    }
  }
}
</script>

<style lang="scss">
  @font-face {
    font-family: lemonMilk;
    src: url('./assets/fonts/LemonMilk.otf') format('opentype');
  }

  * {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
  }

  html, body {
    height: 100%;
    width: 100%;
  }

  body {
    min-height: 100vh;
  }

  .topElements{
    display: flex;
    flex-direction: column;
    flex-grow: 1;
    min-height: 100vh;

    transition: 0.3 ease;

    .breaker {
      width: 80%;
      background: white;
      height: 10px;
      border-radius: 10px;
      margin: 25px auto 0;
    }

    .content-holder-enter-active, content-holder-leave-active {
      animation-delay: 0.4s;
      animation: fade_in 0.7s ease-in-out;
    }
    
  }
  
  router-view{
    min-height: 75vh;
  }

  .defaultBG {
    background: teal;
    position: relative;
  }

  
  @keyframes fade_in {
    0%{
      opacity: 0;
      transform: translateY(25px);
    }
    100%{
      opacity: 1;
      transform: translateY(0px);
    }
    
  }

  @keyframes fade_out {
    0%{
      opacity: 1;
      transform: translateY(0px);
    }
    70%{
      opacity: 0;
      transform: translateY(25px);
    }
    
  }
  

</style>
