<template>
    <div class="articleContainer">
        <div class="articleTitles">
           
                <h3 class="artTitle">{{data.title}}</h3>
                <p class="artDes">{{data.description}}</p>
                <ul>
                    <li v-for="(item, index) in data.keywords" :key="index">
                        {{ item }}
                    </li>
                </ul>
           
        </div>
        <div class="articleBody">

        </div>
    </div>
</template>
<script>
export default {
    name: "Article",
    props: ['data'],
    mounted: function(){
        if(this.data.hero_image.length != 0){
            // need to load in the image from the strapi local host / 'http://localhost:1337'
            // ELSE USE FOR LIVE: 'https://littleleo-cms.herokuapp.com/'
            let strapi = 'https://littleleo-cms.herokuapp.com/'
            let background
            // is there medium?
            if(this.data.hero_image[0].formats.medium){
                background = this.data.hero_image[0].formats.medium.url
            } else if(this.data.hero_image[0].formats.small) {
                background = this.data.hero_image[0].formats.small.url
            } else {
                console.log('No image size is found')
                background = null
            }
            let background_img = `${strapi}${background}`
            console.log(background_img)
            document.querySelector('.articleTitles').style.backgroundImage = `url(${background_img})`
        }else{return}
    }
    
}
</script>
<style lang="scss">
    .articleContainer{
        width: 100%;
        height: 100%;
        margin: 50px 0;
        .articleTitles{
            width: 100%;
            min-height: 25vh;
            background: black;
            color: white;
            font-family: lemonMilk;

            position: relative;

            // style for background once loaded

            background-position: center;
            background-size: cover;
            background-repeat: no-repeat;

            .artTitle {
                position: absolute;
                top: 10px;
                left: 10px;

                background: #0000007d;
                padding: 5px 10px;
            }
            .artDes {
                position: absolute;
                top: 50%;
                left: 50%;
                transform: translate(-50%, -50%);
                width: 80%;
                font-size: 0.8em;

                background: #0000007d;
                padding: 5px 7.5px;
            }
        }
    }
</style>