<template>
  <div class="navigationContainer">
      <div class="languageContainer" v-for="item in articleData" :key="item.id">
          <router-link
          
          :to="{name: 'Articles', params: {id: item.id, article: item.articles}}" 
          @click.native="background(item.id)"
          >
              {{ item.title }}
            </router-link>     
      </div>
  </div>
</template>

<script>
export default {
  name: 'Navbar',
  props: ['articleData'],
  data(){
      return{
        feedback: null
      }
  },
  methods: {
      background: function(payload) {
        //   console.log('Hi there')
        //   console.log(payload)
          this.$emit('backgroundColor', payload)
        //   console.log('Complete')
      },
      noArticles(){
        this.feedback = 'No Articles as of yet, sorry.....'
      }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss">
// set up a grid css rule so that there is only 3 or 4 across but as many as needed down

.navigationContainer {
    font-family: lemonMilk;
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    grid-gap: 1em;
    // background: #2e2e2e;
    padding: 20px 0;
    width: 80%;
    margin: 0 auto;

    @media (min-width: 1080px) {
      grid-template-columns: repeat(6, 1fr);
      grid-gap: 0.5em;
    }

     .languageContainer{

            background-image: url("~@/assets/img/pentagon_star.svg");
            background-repeat: no-repeat;
            background-position: center;
            background-size: contain;
            height: 75px;
            width: auto;

            position: relative;

       
        a{
            text-decoration: none;

            color: #EEE;
            font-family: lemonMilk;

            position: absolute;
            top: 55%;
            left: 50%;

            transform: translate(-50%, -50%);

            cursor: pointer;
            font-size: 1em;
            transition: 0.3s ease;
            text-align: center;
        }
    }
}

</style>
